2	
3	/**
4	 * M44 D2-T4 — gsd-t parallel CLI + mode-aware gating math tests
5	 *
6	 * Covers:
7	 *   - computeInSessionHeadroom: ok case + reduction floor (N=1 fallback)
8	 *   - computeUnattendedGate: ok case + split case
9	 *   - formatPlanTable: header row renders all six expected columns
10	 *   - gate-veto fallback: task with unmet dep is removed from parallel batch
11	 *   - dry-run smoke: table header appears in stdout for runCli()
12	 *
13	 * Per constraints.md: zero external deps, never mutates caller's files
14	 * outside os.tmpdir() fixtures.
15	 */
16	
17	const test = require("node:test");
18	const assert = require("node:assert/strict");
19	const fs = require("node:fs");
20	const os = require("node:os");
21	const path = require("node:path");
22	
23	const {
24	  runParallel,
25	  formatPlanTable,
26	  PLAN_HEADER,
27	  _parseArgv,
28	  _detectMode,
29	} = require("../bin/gsd-t-parallel.cjs");
30	
31	const {
32	  computeInSessionHeadroom,
33	  computeUnattendedGate,
34	  IN_SESSION_CW_CEILING_PCT,
35	  UNATTENDED_PER_WORKER_CW_PCT,
36	  DEFAULT_SUMMARY_SIZE_PCT,
37	} = require("../bin/gsd-t-orchestrator-config.cjs");
38	
39	// ─── fixture helpers ────────────────────────────────────────────────────
40	
41	function mkProject() {
42	  const root = fs.mkdtempSync(path.join(os.tmpdir(), "m44-d2-"));
43	  fs.mkdirSync(path.join(root, ".gsd-t", "domains"), { recursive: true });
44	  fs.mkdirSync(path.join(root, ".gsd-t", "events"), { recursive: true });
45	  return root;
46	}
47	
48	function writeTasks(root, domain, body) {
49	  const dir = path.join(root, ".gsd-t", "domains", domain);
50	  fs.mkdirSync(dir, { recursive: true });
51	  fs.writeFileSync(path.join(dir, "tasks.md"), body);
52	}
53	
54	// ─── computeInSessionHeadroom ──────────────────────────────────────────
55	
56	test("in-session headroom: ok case — fits under ceiling returns requested N", () => {
57	  // ctxPct=30, N=5, summarySize=4 → 30 + 20 = 50 ≤ 85 → ok, reducedCount=5
58	  const r = computeInSessionHeadroom({ ctxPct: 30, workerCount: 5, summarySize: 4 });
59	  assert.equal(r.ok, true);
60	  assert.equal(r.reducedCount, 5);
61	});
62	
63	test("in-session headroom: ceiling exactly 85 is OK (≤, not <)", () => {
64	  // 85 + 0 = 85 ≤ 85 → ok
65	  const r = computeInSessionHeadroom({ ctxPct: 85, workerCount: 0, summarySize: 4 });
66	  assert.equal(r.ok, true);
67	  assert.equal(r.reducedCount, 0);
68	});
69	
70	test("in-session headroom: reduced case — reduces until fits", () => {
71	  // ctxPct=70, summarySize=4: N=5 → 90 fail, N=4 → 86 fail, N=3 → 82 ok
72	  const r = computeInSessionHeadroom({ ctxPct: 70, workerCount: 5, summarySize: 4 });
73	  assert.equal(r.ok, true);
74	  assert.equal(r.reducedCount, 3);
75	});
76	
77	test("in-session headroom: floor is N=1 — NEVER refuses", () => {
78	  // ctxPct=90 already over ceiling. N=1 still returns ok=true, reducedCount=1.
79	  const r = computeInSessionHeadroom({ ctxPct: 90, workerCount: 10, summarySize: 4 });
80	  assert.equal(r.ok, true);
81	  assert.equal(r.reducedCount, 1);
82	});
83	
84	test("in-session headroom: default summarySize uses exported constant", () => {
85	  // workerCount=0 → trivial ok regardless of summarySize default
86	  const r = computeInSessionHeadroom({ ctxPct: 0, workerCount: 0 });
87	  assert.equal(r.ok, true);
88	  assert.equal(r.reducedCount, 0);
89	  assert.equal(DEFAULT_SUMMARY_SIZE_PCT, 4);
90	});
91	
92	// ─── computeUnattendedGate ──────────────────────────────────────────────
93	
94	test("unattended gate: ok case — estimatedCwPct ≤ 60", () => {
95	  const r = computeUnattendedGate({ estimatedCwPct: 55 });
96	  assert.equal(r.ok, true);
97	  assert.equal(r.split, false);
98	});
99	
100	test("unattended gate: split case — estimatedCwPct > 60", () => {
101	  const r = computeUnattendedGate({ estimatedCwPct: 75 });
102	  assert.equal(r.ok, false);
103	  assert.equal(r.split, true);
104	});
105	
106	test("unattended gate: boundary — 60 exactly is OK (>, not ≥)", () => {
107	  const r = computeUnattendedGate({ estimatedCwPct: 60 });
108	  assert.equal(r.ok, true);
109	  assert.equal(r.split, false);
110	});
111	
112	test("unattended gate: custom threshold override", () => {
113	  const r = computeUnattendedGate({ estimatedCwPct: 50, threshold: 40 });
114	  assert.equal(r.ok, false);
115	  assert.equal(r.split, true);
116	});
117	
118	test("exported ceiling constants match contract", () => {
119	  assert.equal(IN_SESSION_CW_CEILING_PCT, 85);
120	  assert.equal(UNATTENDED_PER_WORKER_CW_PCT, 60);
