3	/**
4	 * GSD-T Spawn Plan Writer (M44 D8 T1)
5	 *
6	 * Pure module — writes a spawn-plan JSON file under `.gsd-t/spawns/{spawnId}.json`
7	 * at every spawn chokepoint (captureSpawn, autoSpawnHeadless, unattended-worker
8	 * resume Step 0). The plan file answers exactly one question:
9	 *
10	 *   "Of the tasks that were supposed to happen in this spawn, which are done,
11	 *    which are in flight, which are pending?"
12	 *
13	 * Hard rules (see .gsd-t/domains/m44-d8-spawn-plan-visibility/constraints.md):
14	 *   1. Writer DERIVES, never decides — no LLM calls, no prompts, no heuristics
15	 *      beyond reading partition.md + tasks.md.
16	 *   2. Spawn must launch even if writer fails — callers wrap in try/catch.
17	 *   3. Atomic writes only (temp file + rename).
18	 *
19	 * Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
20	 *
21	 * Zero external deps. `.cjs` so it loads in both ESM-default and CJS projects.
22	 */
23	
24	const fs = require('fs');
25	const path = require('path');
26	
27	const SPAWNS_SUBDIR = path.join('.gsd-t', 'spawns');
28	const SPAWN_PLAN_SCHEMA_VERSION = 1;
29	
30	/**
31	 * Write a spawn-plan file at `.gsd-t/spawns/{spawnId}.json` using an atomic
32	 * temp-file + rename. Creates the `.gsd-t/spawns/` directory and its
33	 * `.gitkeep` sentinel if missing.
34	 *
35	 * If `tasks` or `domains` are not explicitly supplied, the writer tries
36	 * to derive them from `.gsd-t/partition.md` + `.gsd-t/domains/*\/tasks.md`
37	 * via the companion `spawn-plan-derive.cjs` module. When derivation fails
38	 * (no partition file, malformed tasks.md, ENOENT), the writer falls back to
39	 * `{tasks: [], note: "no-partition"}` and STILL writes the file — the
40	 * observability panel's job is to render whatever is present; never to block.
41	 *
42	 * @param {object} opts
43	 * @param {string} opts.spawnId                       filesystem-safe id
44	 * @param {'unattended-worker'|'headless-detached'|'in-session-subagent'} opts.kind
45	 * @param {string} [opts.milestone]                   e.g. 'M44'
46	 * @param {string} [opts.wave]                        e.g. 'wave-3'
47	 * @param {string[]} [opts.domains]                   domain names involved
48	 * @param {Array<{id: string, title: string, status?: string}>} [opts.tasks]
49	 *                                                    explicit task list
50	 *                                                    (bypasses derivation)
51	 * @param {string} [opts.projectDir='.']
52	 * @param {Date}   [opts.now]                         injection for tests
53	 * @returns {string}                                  absolute path written
54	 */
55	function writeSpawnPlan(opts) {
56	  if (!opts || typeof opts !== 'object') {
57	    throw new Error('writeSpawnPlan: opts is required');
58	  }
59	  const spawnId = _sanitizeSpawnId(opts.spawnId);
60	  if (!spawnId) {
61	    throw new Error('writeSpawnPlan: spawnId is required and must be filesystem-safe');
62	  }
63	  const kind = opts.kind || 'in-session-subagent';
64	  const projectDir = opts.projectDir || '.';
65	  const now = opts.now instanceof Date ? opts.now : new Date();
66	
67	  const spawnsDir = path.join(projectDir, SPAWNS_SUBDIR);
68	  _ensureDir(spawnsDir);
69	  _ensureGitkeep(spawnsDir);
70	
71	  // Derive or accept explicit plan slice. Explicit wins.
72	  let plan = _buildPlanSkeleton({ spawnId, kind, now });
73	  plan.milestone = opts.milestone || null;
74	  plan.wave = opts.wave || null;
75	  plan.domains = Array.isArray(opts.domains) ? opts.domains.slice() : [];
76	  plan.tasks = Array.isArray(opts.tasks)
77	    ? opts.tasks.map(_normalizeTask)
78	    : [];
79	
80	  // Only auto-derive when caller did NOT explicitly supply tasks. A caller
81	  // can pass `tasks: []` to bypass derivation too.
82	  if (!Array.isArray(opts.tasks)) {
83	    try {
84	      const derive = require('./spawn-plan-derive.cjs');
85	      const derived = derive.derivePlanFromPartition({
86	        projectDir,
87	        milestone: opts.milestone,
88	        currentIter: opts.currentIter,
89	      });
90	      if (derived && typeof derived === 'object') {
91	        if (!plan.milestone && derived.milestone) plan.milestone = derived.milestone;
92	        if (!plan.wave && derived.wave) plan.wave = derived.wave;
93	        if (!plan.domains.length && Array.isArray(derived.domains)) plan.domains = derived.domains.slice();
94	        if (Array.isArray(derived.tasks)) plan.tasks = derived.tasks.map(_normalizeTask);
95	      }
96	    } catch (err) {
97	      // Derivation failures NEVER block the spawn. The plan file still
98	      // gets written with `{tasks: [], note: "no-partition"}` shape.
99	      plan.note = 'no-partition';
100	      try { process.stderr.write(`[spawn-plan-writer] derive failed (continuing): ${err && err.message || err}\n`); } catch (_) { /* silent */ }
101	    }
102	  }
103	
104	  // Mark first incomplete task as in_progress if every predecessor is done.
105	  // Only one task per spawn may be in_progress at a time (see constraints §Format rules).
106	  _applyInProgressHint(plan.tasks);
107	
108	  const targetPath = path.join(spawnsDir, spawnId + '.json');
109	  const absTarget = path.resolve(targetPath);
110	  _atomicWriteJson(absTarget, plan);
111	  return absTarget;
112	}
113	
114	/**
115	 * Return the `.gsd-t/spawns/` directory for the given project.
116	 */
117	function spawnsDirFor(projectDir) {
118	  return path.join(projectDir || '.', SPAWNS_SUBDIR);
119	}
120	
121	// ── Internal helpers ────────────────────────────────────────────────────────
122	
123	function _sanitizeSpawnId(id) {
124	  if (id == null) return null;
125	  const s = String(id);
126	  // Filesystem-safe: alphanumerics, dash, underscore, dot. See constraints.md §Format rules.
127	  if (!/^[A-Za-z0-9._-]{1,200}$/.test(s)) return null;
128	  return s;
129	}
130	
131	function _ensureDir(d) {
132	  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
133	}
134	
135	function _ensureGitkeep(dir) {
136	  const gk = path.join(dir, '.gitkeep');
137	  if (!fs.existsSync(gk)) {
138	    try { fs.writeFileSync(gk, ''); } catch (_) { /* best-effort */ }
139	  }
140	}
141	
142	function _buildPlanSkeleton({ spawnId, kind, now }) {
143	  return {
144	    schemaVersion: SPAWN_PLAN_SCHEMA_VERSION,
145	    spawnId,
146	    kind,
147	    startedAt: now.toISOString(),
148	    endedAt: null,
149	    milestone: null,
150	    wave: null,
151	    domains: [],
152	    tasks: [],
153	    endedReason: null,
154	  };
155	}
156	
157	function _normalizeTask(t) {
158	  if (!t || typeof t !== 'object') return null;
159	  const id = typeof t.id === 'string' ? t.id : null;
160	  const title = typeof t.title === 'string' ? t.title : '';
161	  const statusIn = typeof t.status === 'string' ? t.status : 'pending';
162	  const status = ['pending', 'in_progress', 'done'].includes(statusIn) ? statusIn : 'pending';
163	  const normalized = {
164	    id,
165	    title,
166	    status,
167	  };
168	  if (typeof t.commit === 'string' && t.commit) normalized.commit = t.commit;
169	  if (t.tokens && typeof t.tokens === 'object') {
170	    normalized.tokens = t.tokens;
171	  } else {
172	    normalized.tokens = null;
173	  }
174	  return normalized;
175	}
176	
177	function _applyInProgressHint(tasks) {
178	  if (!Array.isArray(tasks) || tasks.length === 0) return;
179	  // Already an in_progress? Leave as-is.
180	  if (tasks.some((t) => t && t.status === 'in_progress')) return;
181	  for (const t of tasks) {
182	    if (!t) continue;
183	    if (t.status === 'pending') { t.status = 'in_progress'; return; }
184	    // Skip already-done; continue to next.
185	  }
186	}
187	
188	function _atomicWriteJson(targetPath, obj) {
189	  const tmp = targetPath + '.tmp-' + process.pid + '-' + Date.now();
190	  const json = JSON.stringify(obj, null, 2) + '\n';
191	  fs.writeFileSync(tmp, json);
192	  fs.renameSync(tmp, targetPath);
193	}
194	
195	module.exports = {
196	  writeSpawnPlan,
197	  spawnsDirFor,
198	  SPAWN_PLAN_SCHEMA_VERSION,
199	  // Exposed for unit-test reach-in only; not part of the public contract.
200	  _sanitizeSpawnId,
201	  _normalizeTask,
202	  _applyInProgressHint,
203	  _atomicWriteJson,
204	};
