3	/**
4	 * GSD-T Spawn Plan Status Updater (M44 D8 T2)
5	 *
6	 * Pure module — patches spawn-plan files written by spawn-plan-writer.cjs.
7	 * Called by the post-commit git hook and by `captureSpawn` on completion.
8	 *
9	 * Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
10	 *
11	 * Hard rules:
12	 *   - Atomic rewrites only (temp file + rename)
13	 *   - No-op on unknown spawnId or unknown taskId — observability is best-effort
14	 *   - Never throw for missing files; callers rely on silent-fail behavior
15	 */
16	
17	const fs = require('fs');
18	const path = require('path');
19	
20	const SPAWNS_SUBDIR = path.join('.gsd-t', 'spawns');
21	
22	/**
23	 * Patch `{spawnId}.json`: find the task with the given id and flip its
24	 * status to `done`, recording the commit SHA and (optional) token
25	 * attribution. If the next pending task exists, promote it to
26	 * `in_progress` so the single-active-task invariant is preserved.
27	 *
28	 * @param {object} opts
29	 * @param {string} opts.spawnId
30	 * @param {string} opts.taskId
31	 * @param {string} [opts.commit]                         short or full SHA
32	 * @param {object|null} [opts.tokens]                    `{in,out,cr,cc,cost_usd}` or null
33	 * @param {string} [opts.projectDir='.']
34	 * @returns {{ patched: boolean, path: string }}
35	 */
36	function markTaskDone(opts) {
37	  if (!opts || typeof opts !== 'object') return { patched: false, path: null };
38	  const { spawnId, taskId } = opts;
39	  if (!spawnId || !taskId) return { patched: false, path: null };
40	
41	  const projectDir = opts.projectDir || '.';
42	  const fp = _planPath(projectDir, spawnId);
43	  const plan = _readPlan(fp);
44	  if (!plan) return { patched: false, path: fp };
45	
46	  const tasks = Array.isArray(plan.tasks) ? plan.tasks : [];
47	  const idx = tasks.findIndex((t) => t && t.id === taskId);
48	  if (idx < 0) return { patched: false, path: fp };
49	
50	  const task = tasks[idx];
51	  task.status = 'done';
52	  if (typeof opts.commit === 'string' && opts.commit) task.commit = opts.commit;
53	  // Token attribution is "null when absent" per constraints §Format rules.
54	  // The caller passes `null` or an object; we never silently overwrite
55	  // an already-populated tokens field with null.
56	  if (Object.prototype.hasOwnProperty.call(opts, 'tokens')) {
57	    if (opts.tokens && typeof opts.tokens === 'object') {
58	      task.tokens = _normalizeTokens(opts.tokens);
59	    } else if (task.tokens == null) {
60	      task.tokens = null;
61	    }
62	  }
63	
64	  // Promote the next pending task to in_progress (single-active invariant).
65	  const anyInProgress = tasks.some((t) => t && t.status === 'in_progress');
66	  if (!anyInProgress) {
67	    for (let j = idx + 1; j < tasks.length; j++) {
68	      if (tasks[j] && tasks[j].status === 'pending') {
69	        tasks[j].status = 'in_progress';
70	        break;
71	      }
72	    }
73	  }
74	
75	  _atomicWriteJson(fp, plan);
76	  return { patched: true, path: fp };
77	}
78	
79	/**
80	 * Mark a spawn plan as ended. Sets `endedAt` to now-ISO and records
81	 * `endedReason` ('success' | 'error' | caller-supplied). No-op on missing
82	 * file. Atomic rewrite.
83	 *
84	 * @param {object} opts
85	 * @param {string} opts.spawnId
86	 * @param {string} [opts.endedReason='success']
87	 * @param {string} [opts.projectDir='.']
88	 * @param {Date}   [opts.now]
89	 * @returns {{ patched: boolean, path: string }}
90	 */
91	function markSpawnEnded(opts) {
92	  if (!opts || typeof opts !== 'object') return { patched: false, path: null };
93	  const { spawnId } = opts;
94	  if (!spawnId) return { patched: false, path: null };
95	
96	  const projectDir = opts.projectDir || '.';
97	  const fp = _planPath(projectDir, spawnId);
98	  const plan = _readPlan(fp);
99	  if (!plan) return { patched: false, path: fp };
100	
101	  const now = opts.now instanceof Date ? opts.now : new Date();
102	  plan.endedAt = now.toISOString();
103	  plan.endedReason = opts.endedReason || 'success';
104	  _atomicWriteJson(fp, plan);
105	  return { patched: true, path: fp };
106	}
107	
108	/**
109	 * Enumerate active plan files (those where `endedAt === null`). Returns
110	 * absolute file paths, sorted by startedAt descending.
111	 *
112	 * @param {string} [projectDir='.']
113	 * @returns {string[]}
114	 */
115	function listActivePlans(projectDir) {
116	  const dir = path.join(projectDir || '.', SPAWNS_SUBDIR);
117	  if (!fs.existsSync(dir)) return [];
118	  let files;
119	  try { files = fs.readdirSync(dir); } catch (_) { return []; }
120	  const results = [];
121	  for (const f of files) {
122	    if (!f.endsWith('.json')) continue;
123	    const fp = path.resolve(path.join(dir, f));
124	    const plan = _readPlan(fp);
125	    if (plan && plan.endedAt == null) results.push({ fp, plan });
126	  }
127	  results.sort((a, b) => {
128	    const ta = Date.parse(a.plan && a.plan.startedAt || '') || 0;
129	    const tb = Date.parse(b.plan && b.plan.startedAt || '') || 0;
130	    return tb - ta;
131	  });
132	  return results.map((r) => r.fp);
133	}
134	
135	// ── token-log attribution lookup ───────────────────────────────────────────
136	
137	/**
138	 * Parse `.gsd-t/token-log.md` and return the sum of `{in,out,cr,cc,cost_usd}`
139	 * across all rows whose `Task` column matches the given id and whose
140	 * `Datetime-start` is >= the spawn's startedAt.
141	 *
142	 * Returns `null` when no matching rows exist (per the "zero is a
143	 * measurement, dash is acknowledged gap" rule).
144	 *
145	 * @param {object} opts
146	 * @param {string} opts.projectDir
147	 * @param {string} opts.taskId
148	 * @param {string} opts.spawnStartedAt   ISO-8601 (matches plan.startedAt)
149	 * @param {string} [opts.tokenLogPath]   override for tests
150	 * @returns {{in:number, out:number, cr:number, cc:number, cost_usd:number}|null}
151	 */
152	function sumTokensForTask(opts) {
153	  if (!opts || typeof opts !== 'object') return null;
154	  const { projectDir, taskId } = opts;
155	  if (!projectDir || !taskId) return null;
156	
157	  const fp = opts.tokenLogPath || path.join(projectDir, '.gsd-t', 'token-log.md');
158	  if (!fs.existsSync(fp)) return null;
159	
160	  const startMs = _parseDatetime(opts.spawnStartedAt);
161	
162	  let text;
163	  try { text = fs.readFileSync(fp, 'utf8'); } catch (_) { return null; }
164	
165	  const lines = text.split('\n');
166	  // Find header row to locate column indices.
167	  const headerIdx = lines.findIndex((l) => /^\|\s*Datetime-start\s*\|/.test(l));
168	  if (headerIdx < 0) return null;
169	  const header = lines[headerIdx].split('|').map((s) => s.trim());
170	  const iStart = header.indexOf('Datetime-start');
171	  const iTokens = header.indexOf('Tokens');
172	  const iTask = header.indexOf('Task');
173	  if (iStart < 0 || iTask < 0) return null;
174	
175	  const sum = { in: 0, out: 0, cr: 0, cc: 0, cost_usd: 0 };
176	  let matched = 0;
177	  for (let i = headerIdx + 2; i < lines.length; i++) {
178	    const row = lines[i];
179	    if (!row || !row.startsWith('|')) continue;
180	    const cells = row.split('|').map((s) => s.trim());
181	    if (cells.length < header.length) continue;
182	    const startedAt = cells[iStart] || '';
183	    const task = cells[iTask] || '';
184	    if (task !== taskId) continue;
185	    // Only rows whose Datetime-start >= spawn.startedAt count.
186	    if (startMs != null) {
187	      const rowMs = _parseDatetime(startedAt);
188	      if (rowMs != null && rowMs < startMs) continue;
189	    }
190	    const tokensCell = iTokens >= 0 ? (cells[iTokens] || '') : '';
191	    const parsed = _parseTokensCell(tokensCell);
192	    if (parsed) {
193	      sum.in += parsed.in;
194	      sum.out += parsed.out;
195	      sum.cr += parsed.cr;
196	      sum.cc += parsed.cc;
197	      sum.cost_usd += parsed.cost_usd;
198	      matched++;
199	    } else {
200	      // No token data in the row; still counts as a "match" for the task
201	      // but contributes zero. Keep going.
202	      matched++;
203	    }
204	  }
205	  if (matched === 0) return null;
206	  // Round cost to 2 decimals for determinism.
207	  sum.cost_usd = Math.round(sum.cost_usd * 100) / 100;
208	  return sum;
209	}
210	
211	// ── internal helpers ───────────────────────────────────────────────────────
212	
213	function _planPath(projectDir, spawnId) {
214	  return path.resolve(path.join(projectDir, SPAWNS_SUBDIR, spawnId + '.json'));
215	}
216	
217	function _readPlan(fp) {
218	  try {
219	    const raw = fs.readFileSync(fp, 'utf8');
220	    const parsed = JSON.parse(raw);
221	    if (!parsed || typeof parsed !== 'object') return null;
222	    return parsed;
223	  } catch (_) {
224	    return null;
225	  }
226	}
227	
228	function _atomicWriteJson(targetPath, obj) {
229	  const dir = path.dirname(targetPath);
230	  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
231	  const tmp = targetPath + '.tmp-' + process.pid + '-' + Date.now();
232	  const json = JSON.stringify(obj, null, 2) + '\n';
233	  fs.writeFileSync(tmp, json);
234	  fs.renameSync(tmp, targetPath);
235	}
236	
237	function _normalizeTokens(t) {
238	  const num = (v) => (typeof v === 'number' && Number.isFinite(v) ? v : Number(v) || 0);
239	  return {
240	    in: num(t.in != null ? t.in : t.input_tokens),
241	    out: num(t.out != null ? t.out : t.output_tokens),
242	    cr: num(t.cr != null ? t.cr : t.cache_read_input_tokens),
243	    cc: num(t.cc != null ? t.cc : t.cache_creation_input_tokens),
244	    cost_usd: num(
245	      t.cost_usd != null
246	        ? t.cost_usd
247	        : (t.total_cost_usd != null ? t.total_cost_usd : 0)
248	    ),
249	  };
250	}
251	
252	function _parseDatetime(s) {
253	  if (!s) return null;
254	  if (typeof s === 'string' && /^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/.test(s)) {
255	    const [d, t] = s.split(' ');
256	    const ms = Date.parse(`${d}T${t}:00`);
257	    return Number.isFinite(ms) ? ms : null;
258	  }
259	  const ms = Date.parse(s);
260	  return Number.isFinite(ms) ? ms : null;
261	}
262	
263	/**
264	 * Parse a tokens cell of the form `in=N out=N cr=N cc=N $X.XX` or `—`
265	 * or a mixed form. Returns null when no numeric data is present.
266	 */
267	function _parseTokensCell(cell) {
268	  if (!cell || cell === '—' || cell === '-') return null;
269	  const num = (re) => {
270	    const m = cell.match(re);
271	    return m ? Number(m[1]) : 0;
272	  };
273	  const inp = num(/\bin=(\d+)/);
274	  const out = num(/\bout=(\d+)/);
275	  const cr = num(/\bcr=(\d+)/);
276	  const cc = num(/\bcc=(\d+)/);
277	  const costM = cell.match(/\$(\d+(?:\.\d+)?)/);
278	  const cost_usd = costM ? Number(costM[1]) : 0;
279	  if (!inp && !out && !cr && !cc && !cost_usd) return null;
280	  return { in: inp, out, cr, cc, cost_usd };
281	}
282	
283	module.exports = {
284	  markTaskDone,
285	  markSpawnEnded,
286	  listActivePlans,
287	  sumTokensForTask,
288	  // test-only
289	  _parseTokensCell,
290	  _parseDatetime,
291	  _normalizeTokens,
292	};
