1	#!/usr/bin/env bash
2	# GSD-T Post-Commit Spawn-Plan Hook (M44 D8 T2)
3	#
4	# Greps the latest commit message for every `[M\d+-D\d+-T\d+]` task id and
5	# flips the matching task in every ACTIVE spawn plan under `.gsd-t/spawns/`
6	# to `done` (with commit SHA + token attribution from `.gsd-t/token-log.md`).
7	#
8	# Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
9	#
10	# HARD RULE: silent-fail. This hook must NEVER break the user's commit.
11	# Every error path logs to stderr and exits 0.
12	
13	set +e  # never bail on error — silent-fail is mandatory
14	
15	# Resolve project root (the dir git operates from).
16	PROJECT_DIR="$(git rev-parse --show-toplevel 2>/dev/null)"
17	if [ -z "$PROJECT_DIR" ] || [ ! -d "$PROJECT_DIR/.gsd-t/spawns" ]; then
18	  exit 0
19	fi
20	
21	UPDATER="$PROJECT_DIR/bin/spawn-plan-status-updater.cjs"
22	if [ ! -f "$UPDATER" ]; then
23	  exit 0
24	fi
25	
26	# Require node; log once and continue if absent.
27	if ! command -v node >/dev/null 2>&1; then
28	  echo "[spawn-plan-hook] node not found — skipping" 1>&2
29	  exit 0
30	fi
31	
32	COMMIT_SHA="$(git rev-parse --short HEAD 2>/dev/null)"
33	COMMIT_MSG="$(git log -1 --format=%B 2>/dev/null)"
34	if [ -z "$COMMIT_SHA" ] || [ -z "$COMMIT_MSG" ]; then
35	  exit 0
36	fi
37	
38	# Extract all [M\d+-D\d+-T\d+] ids (unique, preserved order).
39	TASK_IDS="$(printf '%s' "$COMMIT_MSG" | grep -oE '\[M[0-9]+-D[0-9]+-T[0-9]+\]' | sed 's/[][]//g' | awk '!seen[$0]++')"
40	if [ -z "$TASK_IDS" ]; then
41	  exit 0
42	fi
43	
44	# Delegate patching to node. One invocation handles every active plan ×
45	# every task id. Pipes the task-id list via stdin; silent-fails on any
46	# error so the commit is never broken.
47	printf '%s\n' "$TASK_IDS" | node -e '
48	"use strict";
49	try {
50	  const path = require("path");
51	  const fs = require("fs");
52	  const projectDir = process.argv[2];
53	  const commit = process.argv[3];
54	  let raw = "";
55	  process.stdin.setEncoding("utf8");
56	  process.stdin.on("data", (c) => { raw += c; });
57	  process.stdin.on("end", () => {
58	    try {
59	      const taskIds = raw.split("\n").map((s) => s.trim()).filter(Boolean);
60	      if (!taskIds.length) process.exit(0);
61	      const updater = require(path.join(projectDir, "bin", "spawn-plan-status-updater.cjs"));
62	      const activePaths = updater.listActivePlans(projectDir);
63	      if (!activePaths.length) process.exit(0);
64	      for (const fp of activePaths) {
65	        let plan;
66	        try { plan = JSON.parse(fs.readFileSync(fp, "utf8")); } catch (_) { continue; }
67	        const spawnId = plan && plan.spawnId;
68	        const spawnStartedAt = plan && plan.startedAt;
69	        if (!spawnId) continue;
70	        const planTaskIds = new Set((plan.tasks || []).map((t) => t && t.id).filter(Boolean));
71	        for (const taskId of taskIds) {
72	          if (!planTaskIds.has(taskId)) continue;
73	          const tokens = updater.sumTokensForTask({ projectDir, taskId, spawnStartedAt });
74	          updater.markTaskDone({ spawnId, taskId, commit, tokens, projectDir });
75	        }
76	      }
77	    } catch (err) {
78	      try { process.stderr.write("[spawn-plan-hook] " + String(err && err.message || err) + "\n"); } catch (_) { /* silent */ }
79	    }
80	  });
81	} catch (err) {
82	  try { process.stderr.write("[spawn-plan-hook] " + String(err && err.message || err) + "\n"); } catch (_) { /* silent */ }
83	}
84	' "$PROJECT_DIR" "$COMMIT_SHA" 2>/dev/null
85	
86	exit 0
