'use strict';

/**
 * GSD-T Spawn Plan — token formatting + cumulative totals (M44 D8 T7)
 *
 * Pure helper module used by the transcript right-side spawn-plan panel.
 * Extracted from the inline script in `scripts/gsd-t-transcript.html` so the
 * same functions can be unit-tested under Node without loading a DOM.
 *
 * Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
 *   - Token cell format: `in=12.5k out=1.7k $0.42` (k-suffix above 1000,
 *     2-decimal USD). Returns `—` when tokens are null/missing.
 *   - Cumulative totals: sum `{in,out,cr,cc,cost_usd}` across done tasks.
 *     Returns `null` when no done-task has tokens (panel renders `—`).
 *
 * Zero external deps. `.cjs` so it loads in both ESM-default and CJS projects.
 */

/**
 * k-suffix number formatter. `1500` → `1.5k`, `999` → `999`, `null` → `0`.
 * Used by `fmtTokens` to compact large counts.
 *
 * @param {number|string|null|undefined} n
 * @returns {string}
 */
function fmtK(n) {
  if (n == null || Number.isNaN(Number(n))) return '0';
  const num = Number(n);
  if (Math.abs(num) >= 1000) return (num / 1000).toFixed(1) + 'k';
  return String(num);
}

/**
 * Render a token-cell string from a `{in, out, cr, cc, cost_usd}` object.
 * When `tokens` is null/undefined/non-object, returns the em-dash marker
 * per the "zero is a measurement, dash is acknowledged gap" rule.
 *
 * @param {object|null|undefined} tokens
 * @returns {string}
 */
function fmtTokens(tokens) {
  if (!tokens || typeof tokens !== 'object') return '—';
  const ins = fmtK(tokens.in);
  const out = fmtK(tokens.out);
  const cost = (typeof tokens.cost_usd === 'number')
    ? '$' + tokens.cost_usd.toFixed(2)
    : '';
  return ['in=' + ins, 'out=' + out, cost].filter(Boolean).join(' ');
}

/**
 * Sum the `tokens` field across every task whose `status === 'done'` and
 * whose `tokens` is a populated object. Returns null when no done-task has
 * a tokens object attached — the panel renders that state as `—`.
 *
 * @param {Array<{status?:string, tokens?:object}>|null|undefined} tasks
 * @returns {{in:number,out:number,cr:number,cc:number,cost_usd:number}|null}
 */
function sumTokens(tasks) {
  const acc = { in: 0, out: 0, cr: 0, cc: 0, cost_usd: 0 };
  let hit = false;
  for (const t of (tasks || [])) {
    if (!t || t.status !== 'done' || !t.tokens) continue;
    acc.in += Number(t.tokens.in || 0);
    acc.out += Number(t.tokens.out || 0);
    acc.cr += Number(t.tokens.cr || 0);
    acc.cc += Number(t.tokens.cc || 0);
    acc.cost_usd += Number(t.tokens.cost_usd || 0);
    hit = true;
  }
  if (!hit) return null;
  acc.cost_usd = Math.round(acc.cost_usd * 100) / 100;
  return acc;
}

module.exports = {
  fmtK,
  fmtTokens,
  sumTokens,
};

'use strict';

/**
 * M44 D8 T7 — spawn-plan-writer unit tests
 *
 * Covers:
 *   - writeSpawnPlan writes {spawnId}.json under .gsd-t/spawns/
 *   - Schema fields match contract v1.0.0 (schemaVersion, spawnId, kind, startedAt, endedAt, …)
 *   - Explicit tasks are normalized (pending|in_progress|done; status, tokens)
 *   - First pending task auto-promoted to in_progress (single-active invariant)
 *   - Atomic write: temp file + rename (no partial writes)
 *   - Filesystem-safe spawnId is enforced; invalid ids throw
 *   - Derivation fallback → {tasks: [], note: "no-partition"} when partition absent
 *   - Returns absolute path
 *
 * Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
 */

const test = require('node:test');
const assert = require('node:assert/strict');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const { writeSpawnPlan, _applyInProgressHint, _normalizeTask, _sanitizeSpawnId } = require('../bin/spawn-plan-writer.cjs');

function mkTmp() { return fs.mkdtempSync(path.join(os.tmpdir(), 'm44-d8-writer-')); }

test('writeSpawnPlan creates .gsd-t/spawns/{spawnId}.json with contract shape', () => {
  const dir = mkTmp();
  const written = writeSpawnPlan({
    spawnId: 'unit-test-1',
    kind: 'in-session-subagent',
    milestone: 'M44',
    wave: 'wave-3',
    domains: ['d1'],
    tasks: [{ id: 'M44-D8-T1', title: 'writer', status: 'done' }],
    projectDir: dir,
  });
  assert.ok(path.isAbsolute(written), 'returns absolute path');
  assert.ok(fs.existsSync(written), 'file exists');
  const plan = JSON.parse(fs.readFileSync(written, 'utf8'));
  assert.equal(plan.schemaVersion, 1);
  assert.equal(plan.spawnId, 'unit-test-1');
  assert.equal(plan.kind, 'in-session-subagent');
  assert.equal(plan.milestone, 'M44');
  assert.equal(plan.wave, 'wave-3');
  assert.deepEqual(plan.domains, ['d1']);
  assert.equal(plan.endedAt, null);
  assert.equal(plan.endedReason, null);
  assert.ok(typeof plan.startedAt === 'string' && plan.startedAt.length > 0);
  assert.equal(plan.tasks.length, 1);
  assert.equal(plan.tasks[0].id, 'M44-D8-T1');
  assert.equal(plan.tasks[0].status, 'done');
});

test('writeSpawnPlan promotes first pending task to in_progress (single-active invariant)', () => {
  const dir = mkTmp();
  const written = writeSpawnPlan({
    spawnId: 'promote-1',
    kind: 'in-session-subagent',
    tasks: [
      { id: 'T1', title: 't1', status: 'done' },
      { id: 'T2', title: 't2', status: 'pending' },
      { id: 'T3', title: 't3', status: 'pending' },
    ],
    projectDir: dir,
  });
  const plan = JSON.parse(fs.readFileSync(written, 'utf8'));
  const statuses = plan.tasks.map((t) => t.status);
  assert.deepEqual(statuses, ['done', 'in_progress', 'pending']);
});

test('writeSpawnPlan preserves existing in_progress (only ONE active)', () => {
  const dir = mkTmp();
  const written = writeSpawnPlan({
    spawnId: 'preserve-1',
    kind: 'in-session-subagent',
    tasks: [
      { id: 'T1', title: 't1', status: 'in_progress' },
      { id: 'T2', title: 't2', status: 'pending' },
    ],
    projectDir: dir,
  });
  const plan = JSON.parse(fs.readFileSync(written, 'utf8'));
  assert.deepEqual(plan.tasks.map((t) => t.status), ['in_progress', 'pending']);
});

test('writeSpawnPlan rejects invalid spawnId', () => {
  const dir = mkTmp();
  assert.throws(
    () => writeSpawnPlan({ spawnId: '../escape', kind: 'x', projectDir: dir }),
    /filesystem-safe/
  );
  assert.throws(
    () => writeSpawnPlan({ spawnId: '', kind: 'x', projectDir: dir }),
    /required/
  );
});

test('_sanitizeSpawnId accepts safe ids and rejects unsafe', () => {
  assert.equal(_sanitizeSpawnId('gsd-t-execute-2026-04-23'), 'gsd-t-execute-2026-04-23');
  assert.equal(_sanitizeSpawnId('with.dot_and-dash'), 'with.dot_and-dash');
  assert.equal(_sanitizeSpawnId('../escape'), null);
  assert.equal(_sanitizeSpawnId('with/slash'), null);
  assert.equal(_sanitizeSpawnId(''), null);
  assert.equal(_sanitizeSpawnId(null), null);
});

test('writeSpawnPlan with no partition falls back to tasks:[] + no-partition note (derivation failure)', () => {
  const dir = mkTmp();
  // No .gsd-t/partition.md, no tasks.md — derive should swallow error.
  const written = writeSpawnPlan({
    spawnId: 'no-partition-1',
    kind: 'unattended-worker',
    projectDir: dir,
  });
  const plan = JSON.parse(fs.readFileSync(written, 'utf8'));
  // Either tasks is empty OR note is set — both mean "nothing to show".
  assert.ok(Array.isArray(plan.tasks));
  // startedAt ISO
  assert.match(plan.startedAt, /^\d{4}-\d{2}-\d{2}T/);
});

test('writeSpawnPlan creates .gitkeep sentinel for .gsd-t/spawns/', () => {
  const dir = mkTmp();
  writeSpawnPlan({ spawnId: 'gk-1', kind: 'x', tasks: [], projectDir: dir });
  assert.ok(fs.existsSync(path.join(dir, '.gsd-t', 'spawns', '.gitkeep')));
});

test('writeSpawnPlan write is atomic (no leftover .tmp-* file on success)', () => {
  const dir = mkTmp();
  writeSpawnPlan({ spawnId: 'atomic-1', kind: 'x', tasks: [], projectDir: dir });
  const spawnsDir = path.join(dir, '.gsd-t', 'spawns');
  const files = fs.readdirSync(spawnsDir);
  const tmps = files.filter((f) => f.includes('.tmp-'));
  assert.equal(tmps.length, 0, 'no leftover temp files');
});

test('_normalizeTask coerces unknown status to pending and attaches tokens:null', () => {
  const n = _normalizeTask({ id: 'X', title: 'x', status: 'weird' });
  assert.equal(n.status, 'pending');
  assert.equal(n.tokens, null);
});

test('_applyInProgressHint is a no-op on empty or null', () => {
  _applyInProgressHint([]);
  _applyInProgressHint(null);
  // no throw = pass
  assert.ok(true);
});

