'use strict';

/**
 * M44 D8 T7 — transcript renderer panel tests
 *
 * Covers:
 *   - fmtTokens helper renders `in=12.5k out=1.7k $0.42` (k-suffix, 2-decimal USD)
 *   - fmtTokens returns `—` for null/undefined/non-object
 *   - fmtK: sub-1000 → plain digits; ≥1000 → `N.Nk`
 *   - sumTokens sums across done tasks only; returns null when nothing done has tokens
 *   - cost_usd cumulation rounds to 2 decimals (no float drift)
 *   - The transcript HTML embeds the same helpers inline so the right-side
 *     panel renders without loading this .cjs module in the browser — guard
 *     against drift by string-inspecting the HTML.
 *
 * Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
 */

const test = require('node:test');
const assert = require('node:assert/strict');
const fs = require('node:fs');
const path = require('node:path');

const { fmtK, fmtTokens, sumTokens } =
  require('../scripts/spawn-plan-fmt-tokens.cjs');

const TRANSCRIPT_HTML = path.join(__dirname, '..', 'scripts', 'gsd-t-transcript.html');

// ── fmtK ────────────────────────────────────────────────────────────────────

test('fmtK renders sub-1000 as plain digits', () => {
  assert.equal(fmtK(0), '0');
  assert.equal(fmtK(1), '1');
  assert.equal(fmtK(999), '999');
});

test('fmtK renders ≥1000 with k-suffix and one decimal', () => {
  assert.equal(fmtK(1000), '1.0k');
  assert.equal(fmtK(12500), '12.5k');
  assert.equal(fmtK(1742), '1.7k');
});

test('fmtK handles null/undefined/NaN as 0', () => {
  assert.equal(fmtK(null), '0');
  assert.equal(fmtK(undefined), '0');
  assert.equal(fmtK(NaN), '0');
  assert.equal(fmtK('not-a-number'), '0');
});

test('fmtK handles negatives symmetrically', () => {
  assert.equal(fmtK(-1500), '-1.5k');
  assert.equal(fmtK(-42), '-42');
});

// ── fmtTokens ───────────────────────────────────────────────────────────────

test('fmtTokens renders the contract-canonical cell string', () => {
  const out = fmtTokens({ in: 12500, out: 1742, cr: 308, cc: 134046, cost_usd: 0.42 });
  assert.equal(out, 'in=12.5k out=1.7k $0.42');
});

test('fmtTokens returns em-dash for null/undefined/non-object', () => {
  assert.equal(fmtTokens(null), '—');
  assert.equal(fmtTokens(undefined), '—');
  assert.equal(fmtTokens(0), '—');
  assert.equal(fmtTokens('ignored'), '—');
});

test('fmtTokens omits $ segment when cost_usd is missing or non-numeric', () => {
  assert.equal(fmtTokens({ in: 10, out: 5 }), 'in=10 out=5');
  assert.equal(fmtTokens({ in: 10, out: 5, cost_usd: 'bad' }), 'in=10 out=5');
});

test('fmtTokens formats cost to 2 decimals', () => {
  assert.equal(fmtTokens({ in: 0, out: 0, cost_usd: 1 }), 'in=0 out=0 $1.00');
  assert.equal(fmtTokens({ in: 0, out: 0, cost_usd: 0.4 }), 'in=0 out=0 $0.40');
  assert.equal(fmtTokens({ in: 0, out: 0, cost_usd: 0.4249 }), 'in=0 out=0 $0.42');
});

// ── sumTokens (cumulative totals) ───────────────────────────────────────────

test('sumTokens sums only done tasks with populated tokens', () => {
  const tasks = [
    { status: 'done', tokens: { in: 100, out: 50, cr: 10, cc: 5, cost_usd: 0.25 } },
    { status: 'in_progress', tokens: { in: 999, out: 999 } }, // ignored (not done)
    { status: 'pending' }, // ignored
    { status: 'done', tokens: null }, // ignored (no tokens)
    { status: 'done', tokens: { in: 200, out: 100, cr: 20, cc: 10, cost_usd: 0.50 } },
  ];
  const sum = sumTokens(tasks);
  assert.deepEqual(sum, { in: 300, out: 150, cr: 30, cc: 15, cost_usd: 0.75 });
});

test('sumTokens returns null when no done task has tokens', () => {
  assert.equal(sumTokens([]), null);
  assert.equal(sumTokens(null), null);
  assert.equal(sumTokens([{ status: 'pending' }, { status: 'in_progress' }]), null);
  assert.equal(sumTokens([{ status: 'done', tokens: null }]), null);
});

test('sumTokens rounds cost to 2 decimals (no float drift)', () => {
  const tasks = [
    { status: 'done', tokens: { in: 0, out: 0, cr: 0, cc: 0, cost_usd: 0.1 } },
    { status: 'done', tokens: { in: 0, out: 0, cr: 0, cc: 0, cost_usd: 0.2 } },
  ];
  const sum = sumTokens(tasks);
  assert.equal(sum.cost_usd, 0.3, 'cost rounded cleanly');
});

// ── drift guard: the transcript HTML carries the same helpers inline ────────

test('transcript HTML contains the fmtTokens renderer + panel markers', () => {
  assert.ok(fs.existsSync(TRANSCRIPT_HTML), 'transcript.html present');
  const html = fs.readFileSync(TRANSCRIPT_HTML, 'utf8');

  // Panel structure (contract §Reader: `<aside class="spawn-panel">` with two sections)
  assert.match(html, /<aside\s+class="spawn-panel"/);
  assert.match(html, /id="spawn-layer-project"/);
  assert.match(html, /id="spawn-layer-active"/);

  // Status icon mapping per contract (☐ pending, ◐ in_progress, ✓ done)
  assert.match(html, /['"]pending['"]\s*:\s*['"]☐['"]/);
  assert.match(html, /['"]in_progress['"]\s*:\s*['"]◐['"]/);
  assert.match(html, /['"]done['"]\s*:\s*['"]✓['"]/);

  // fmtTokens + fmtK helpers inline (same contract strings our .cjs tests enforce)
  assert.match(html, /function\s+fmtTokens\s*\(/);
  assert.match(html, /function\s+fmtK\s*\(/);

  // SSE consumer for spawn-plan-update channel (per contract §Reader)
  assert.match(html, /\/api\/spawn-plans\/stream/);
  assert.match(html, /\/api\/spawn-plans['"]/);
});

test('transcript HTML renders cumulative totals on both layer headers', () => {
  const html = fs.readFileSync(TRANSCRIPT_HTML, 'utf8');
  assert.match(html, /id="project-totals"/);
  assert.match(html, /id="active-totals"/);
  // sumTokens used to populate headers
  assert.match(html, /function\s+sumTokens\s*\(/);
});

